// Normalize and deduplicate feed items from all RSS sources
const allItems = $input.all();
const normalized = [];
const seenUrls = new Set();

for (const item of allItems) {
  const data = item.json;
  const url = data.link || data.url || data.id || '';

  // Skip duplicates
  if (seenUrls.has(url)) continue;
  seenUrls.add(url);

  normalized.push({
    title: data.title || 'Untitled',
    description: (data.description || data.summary || data.content || '').substring(0, 2000),
    url: url,
    source: data._feedSource || 'regulatory_feed',
    published_date: data.pubDate || data.published || data.updated || new Date().toISOString(),
    author: data.author || data.creator || 'Unknown',
    categories: data.categories || [],
    raw_content: (data.content || data.description || '').substring(0, 5000)
  });
}

return [{
  json: {
    items: normalized,
    item_count: normalized.length,
    polled_at: new Date().toISOString()
  }
}];

