// Match classified regulatory items against organization's portfolio
const geminiResponse = $input.first().json;
const feedData = $('Normalize Feed Items').first().json;

let classifiedItems = [];
try {
  const text = geminiResponse.candidates[0].content.parts[0].text;
  const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  classifiedItems = JSON.parse(cleaned);
} catch (e) {
  classifiedItems = [];
}

// Merge classifications back with original feed data
const itemsByUrl = {};
for (const item of (feedData.items || [])) {
  itemsByUrl[item.url] = item;
}

const alerts = classifiedItems.map((classified, idx) => {
  const original = itemsByUrl[classified.url] || feedData.items[idx] || {};
  return {
    alert_id: `reg_${Date.now()}_${idx}`,
    title: original.title || classified.summary || 'Regulatory Update',
    url: classified.url || original.url || '',
    source: original.source || 'regulatory_feed',
    published_date: original.published_date,
    severity: classified.severity || 'low',
    industries: classified.industries || [],
    jurisdictions: classified.jurisdictions || [],
    compliance_areas: classified.compliance_areas || [],
    action_required: classified.action_required || false,
    summary: classified.summary || '',
    effective_date: classified.effective_date || null,
    matched: true,
    created_at: new Date().toISOString()
  };
});

const highSeverity = alerts.filter(a => a.severity === 'critical' || a.severity === 'high');

return [{
  json: {
    alerts: alerts,
    high_severity_alerts: highSeverity,
    has_high_severity: highSeverity.length > 0,
    total_alerts: alerts.length,
    high_severity_count: highSeverity.length,
    polled_at: feedData.polled_at
  }
}];
